        Cli::try_parse_from(args).unwrap_err().to_string()
    }

    #[test]
    fn chid_defaults() {
        let cli = parse(&["vc-x1", "chid"]);
        if let Commands::Chid(args) = cli.command {
            assert_eq!(args.revision, "@");
