134→/// Indent all lines after the first by `n` spaces.
135→///
136→/// Returns the string unchanged if `n == 0` or there is only one line.
137→pub fn indent_body(s: &str, n: usize) -> String {
138→    if n == 0 {
139→        return s.to_string();
140→    }
141→    let pad = " ".repeat(n);
142→    let mut lines = s.lines();
143→    let mut result = match lines.next() {
144→        Some(first) => first.to_string(),
145→        None => return String::new(),
146→    };
147→    for line in lines {
148→        result.push('\n');
149→        if !line.is_empty() {
150→            result.push_str(&pad);
151→        }
152→        result.push_str(line);
153→    }
154→    result
155→}
