273→/// Parse and evaluate a revset string, returning commit IDs.
274→pub fn resolve_revset(
275→    workspace: &Workspace,
276→    repo: &Arc<ReadonlyRepo>,
277→    revset_str: &str,
278→) -> Result<Vec<CommitId>, Box<dyn std::error::Error>> {
279→    let aliases_map = RevsetAliasesMap::new();
280→    let fileset_aliases_map = FilesetAliasesMap::new();
281→    let extensions = RevsetExtensions::default();
282→    let workspace_root = workspace.workspace_root().to_path_buf();
283→    let path_converter = RepoPathUiConverter::Fs {
284→        cwd: workspace_root.clone(),
285→        base: workspace_root,
286→    };
287→    let workspace_name = workspace.workspace_name();
288→    let workspace_ctx = RevsetWorkspaceContext {
289→        path_converter: &path_converter,
290→        workspace_name,
291→    };
292→    let context = RevsetParseContext {
293→        aliases_map: &aliases_map,
294→        local_variables: HashMap::new(),
295→        user_email: "",
296→        date_pattern_context: chrono::Utc::now().fixed_offset().into(),
297→        default_ignored_remote: None,
298→        fileset_aliases_map: &fileset_aliases_map,
299→        use_glob_by_default: false,
300→        extensions: &extensions,
301→        workspace: Some(workspace_ctx),
302→    };
303→
304→    let mut diagnostics = RevsetDiagnostics::new();
305→    let expression = jj_lib::revset::parse(&mut diagnostics, revset_str, &context)?;
306→
307→    let no_extensions: &[Box<dyn jj_lib::revset::SymbolResolverExtension>] = &[];
308→    let symbol_resolver = SymbolResolver::new(repo.as_ref(), no_extensions);
309→    let resolved = expression.resolve_user_expression(repo.as_ref(), &symbol_resolver)?;
310→    let revset = resolved.evaluate(repo.as_ref())?;
311→
312→    let mut commit_ids = Vec::new();
313→    for result in revset.iter() {
314→        commit_ids.push(result?);
315→    }
316→    Ok(commit_ids)
317→}
