 17→/// Parsed file limit: None (suppress), Some(n) (cap at n), or all.
 18→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 19→pub enum FileLimit {
 20→    /// Don't show changed files section at all.
 21→    None,
 22→    /// Show up to N files (with first/last split if truncated).
 23→    Cap(usize),
 24→    /// Show all files.
 25→    All,
 26→}
 27→
 28→impl FileLimit {
 29→    fn parse(s: &str) -> Result<Self, String> {
 30→        match s {
 31→            "0" => Ok(FileLimit::None),
 32→            "all" => Ok(FileLimit::All),
 33→            _ => s
 34→                .parse::<usize>()
 35→                .map(FileLimit::Cap)
 36→                .map_err(|_| format!("invalid file limit '{s}': expected number, 0, or 'all'")),
 37→        }
 38→    }
 39→}
