 21→/// Result of parsing positional `..` notation.
 22→///
 23→/// Counts are `Some(0)` for closed sides and `None` for open (dotted) sides.
 24→/// Open sides become unlimited unless a positional count is applied later.
 25→#[derive(Debug, Clone, PartialEq, Eq)]
 26→pub struct DotSpec {
 27→    /// The bare revision (without `..`).
 28→    pub rev: String,
 29→    /// Descendant count: `None` = open (dotted), `Some(0)` = closed.
 30→    pub desc_count: Option<usize>,
 31→    /// Ancestor count: `None` = open (dotted), `Some(0)` = closed.
 32→    pub anc_count: Option<usize>,
 33→}
 34→
 35→/// Parse a positional REV string for `..` notation.
 36→///
 37→/// Returns the bare revision with open/closed counts per side.
 38→/// `None` means the side had dots (open for expansion);
 39→/// `Some(0)` means no dots on that side (closed).
 40→/// Actual counts are applied later from positional args.
 41→pub fn parse_dot_rev(rev: &str) -> DotSpec {
 42→    if let Some(inner) = rev.strip_prefix("..").and_then(|s| s.strip_suffix("..")) {
 43→        DotSpec {
 44→            rev: inner.to_string(),
 45→            desc_count: None,
 46→            anc_count: None,
 47→        }
 48→    } else if let Some(inner) = rev.strip_prefix("..") {
 49→        DotSpec {
 50→            rev: inner.to_string(),
 51→            desc_count: None,
 52→            anc_count: Some(0),
 53→        }
 54→    } else if let Some(inner) = rev.strip_suffix("..") {
 55→        DotSpec {
 56→            rev: inner.to_string(),
 57→            desc_count: Some(0),
 58→            anc_count: None,
 59→        }
 60→    } else {
 61→        DotSpec {
 62→            rev: rev.to_string(),
 63→            desc_count: Some(0),
 64→            anc_count: Some(0),
 65→        }
 66→    }
 67→}
 68→
 69→/// Resolve positional and flag args into a `DotSpec` ready for `collect_ids`.
 70→///
 71→/// Handles: dot notation parsing, flag vs positional precedence,
 72→/// count-means-total semantics (subtracts 1 for anchor).
 73→pub fn resolve_spec(
 74→    pos_rev: Option<&str>,
 75→    pos_count: Option<usize>,
 76→    flag_rev: &str,
 77→    flag_limit: Option<usize>,
 78→    default_rev: &str,
 79→) -> DotSpec {
 80→    let flag_rev_set = flag_rev != default_rev;
 81→    let rev_str = if flag_rev_set {
 82→        flag_rev
 83→    } else {
 84→        pos_rev.unwrap_or(default_rev)
 85→    };
 86→    let mut spec = parse_dot_rev(rev_str);
 87→
 88→    let count = if flag_limit.is_some() {
 89→        flag_limit
 90→    } else {
 91→        pos_count
 92→    };
 93→
 94→    if let Some(c) = count {
 95→        let n = c.saturating_sub(1);
 96→        let both_open = spec.desc_count.is_none() && spec.anc_count.is_none();
 97→        if both_open {
 98→            // Split budget across both sides: ancestors get the extra
 99→            let desc_n = n / 2;
100→            let anc_n = n - desc_n;
101→            spec.desc_count = Some(desc_n);
102→            spec.anc_count = Some(anc_n);
103→        } else {
104→            if spec.desc_count.is_none() {
105→                spec.desc_count = Some(n);
106→            }
107→            if spec.anc_count.is_none() {
108→                spec.anc_count = Some(n);
109→            }
110→            // bare `x 5` → treat as `x.. 5` (ancestors)
111→            if spec.desc_count == Some(0) && spec.anc_count == Some(0) {
112→                spec.anc_count = Some(n);
113→            }
114→        }
115→    }
116→
117→    spec
118→}
