198→/// Collect commit IDs for `..x..` (both directions) or any dot notation.
199→///
200→/// Returns `(commit_ids, anchor_index)` — the IDs in display order
201→/// (descendants closest to anchor, anchor, ancestors closest to anchor)
202→/// and the index of the anchor commit within the list.
203→///
204→/// - `desc_count`: `Some(n)` = n closest descendants, `None` = all, `Some(0)` = none
205→/// - `anc_count`: `Some(n)` = n closest ancestors, `None` = all, `Some(0)` = none
206→pub fn collect_ids(
207→    workspace: &Workspace,
208→    repo: &Arc<ReadonlyRepo>,
209→    rev: &str,
210→    desc_count: Option<usize>,
211→    anc_count: Option<usize>,
212→) -> Result<(Vec<CommitId>, usize), Box<dyn std::error::Error>> {
213→    let anchor_ids = resolve_revset(workspace, repo, rev)?;
214→    if anchor_ids.is_empty() {
215→        return Err(format!("no commit found for revision '{rev}'").into());
216→    }
217→    let anchor_id = &anchor_ids[0];
218→    let root_commit_id = repo.store().root_commit_id().clone();
219→
220→    // Descendants (closest to anchor)
221→    let mut desc_ids: Vec<CommitId> = Vec::new();
222→    if desc_count != Some(0) {
223→        let descendant_ids = resolve_revset(workspace, repo, &format!("{rev}::"))?;
224→        desc_ids = descendant_ids
225→            .into_iter()
226→            .filter(|id| *id != root_commit_id && *id != *anchor_id)
227→            .collect();
228→        if let Some(n) = desc_count {
229→            let start = desc_ids.len().saturating_sub(n);
230→            desc_ids = desc_ids[start..].to_vec();
231→        }
232→    }
233→
234→    // Ancestors (closest to anchor)
235→    let mut anc_ids: Vec<CommitId> = Vec::new();
236→    if anc_count != Some(0) {
237→        let ancestor_ids = resolve_revset(workspace, repo, &format!("::{rev}"))?;
238→        let limit = anc_count.unwrap_or(usize::MAX);
239→        let mut count = 0;
240→        for commit_id in ancestor_ids {
241→            if commit_id == root_commit_id || commit_id == *anchor_id {
242→                continue;
243→            }
244→            anc_ids.push(commit_id);
245→            count += 1;
246→            if count >= limit {
247→                break;
248→            }
249→        }
250→    }
251→
252→    let anchor_index = desc_ids.len();
253→    let mut result = desc_ids;
254→    result.push(anchor_id.clone());
255→    result.extend(anc_ids);
256→    Ok((result, anchor_index))
257→}
