 12→#[derive(Parser, Debug)]
 13→#[command(version, about = "vc-x1: jj workspace tooling")]
 14→pub struct Cli {
 15→    #[command(subcommand)]
 16→    command: Commands,
 17→}
 18→
 19→#[derive(Subcommand, Debug)]
 20→enum Commands {
 21→    /// Print the changeID for a revision
 22→    Chid(chid::ChidArgs),
 23→
 24→    /// Show full description of a commit
 25→    Desc(desc::DescArgs),
 26→
 27→    /// List commits in a jj repo
 28→    List(list::ListArgs),
 29→
 30→    /// Show commit details and diff summary
 31→    Show(show::ShowArgs),
 32→
 33→    /// Squash working copy into target commit
 34→    Finalize(finalize::FinalizeArgs),
 35→}
 36→
 37→fn main() -> ExitCode {
 38→    let cli = Cli::parse();
 39→
 40→    match cli.command {
 41→        Commands::Chid(args) => {
 42→            if let Err(e) = chid::chid(&args) {
 43→                eprintln!("error: {e}");
 44→                return ExitCode::FAILURE;
 45→            }
 46→            ExitCode::SUCCESS
 47→        }
 48→        Commands::Desc(args) => {
 49→            if let Err(e) = desc::desc(&args) {
 50→                eprintln!("error: {e}");
 51→                return ExitCode::FAILURE;
 52→            }
 53→            ExitCode::SUCCESS
 54→        }
 55→        Commands::List(args) => {
 56→            if let Err(e) = list::list(&args) {
 57→                eprintln!("error: {e}");
 58→                return ExitCode::FAILURE;
 59→            }
 60→            ExitCode::SUCCESS
 61→        }
 62→        Commands::Show(args) => {
 63→            if let Err(e) = show::show(&args) {
 64→                eprintln!("error: {e}");
 65→                return ExitCode::FAILURE;
 66→            }
 67→            ExitCode::SUCCESS
 68→        }
 69→        Commands::Finalize(args) => {
 70→            let opts = args.into_opts();
 71→            finalize::log_msg(&opts.log, "main: finalize entry");
 72→            match finalize::finalize(&opts) {
 73→                Ok(()) => {
 74→                    finalize::log_msg(&opts.log, "main: finalize exit ok");
 75→                    ExitCode::SUCCESS
 76→                }
 77→                Err(e) => {
 78→                    finalize::log_msg(&opts.log, &format!("main: finalize exit err={e}"));
 79→                    eprintln!("error: {e}");
 80→                    ExitCode::FAILURE
 81→                }
 82→            }
 83→        }
 84→    }
 85→}
