 17→/// Parsed file limit: None (suppress), Some(n) (cap at n), or all.
 18→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 19→pub enum FileLimit {
 20→    /// Don't show changed files section at all.
 21→    None,
 22→    /// Show up to N files (with first/last split if truncated).
 23→    Cap(usize),
 24→    /// Show all files.
 25→    All,
 26→}
 27→
 28→impl FileLimit {
 29→    fn parse(s: &str) -> Result<Self, String> {
 30→        match s {
 31→            "0" => Ok(FileLimit::None),
 32→            "all" => Ok(FileLimit::All),
 33→            _ => s
 34→                .parse::<usize>()
 35→                .map(FileLimit::Cap)
 36→                .map_err(|_| format!("invalid file limit '{s}': expected number, 0, or 'all'")),
 37→        }
 38→    }
 39→}
 40→
 41→#[derive(Args, Debug)]
 42→pub struct ShowArgs {
 43→    /// Revision (with optional .. notation)
 44→    #[arg(value_name = "REVISION")]
 45→    pub pos_rev: Option<String>,
 46→
 47→    /// Number of commits to show (per dotted side)
 48→    #[arg(value_name = "COMMITS")]
 49→    pub pos_count: Option<usize>,
 50→
 51→    /// Revision to show (default: @)
 52→    #[arg(short, long, default_value = "@")]
 53→    pub revision: String,
 54→
 55→    /// Max changed files: number, 0 (none), or 'all' (default: 50)
 56→    #[arg(short = 'f', long = "files", default_value = "50")]
 57→    pub files: String,
 58→
 59→    /// Number of commits to show
 60→    #[arg(
 61→        short = 'n',
 62→        long = "commits",
 63→        alias = "limit",
 64→        short_alias = 'l',
 65→        value_name = "COMMITS"
 66→    )]
 67→    pub limit: Option<usize>,
 68→
 69→    /// Path to jj repo (default: current directory)
 70→    #[arg(short = 'R', long, default_value = ".")]
 71→    pub repo: PathBuf,
 72→}
 73→
 74→pub fn show(args: &ShowArgs) -> Result<(), Box<dyn std::error::Error>> {
 75→    let file_limit = FileLimit::parse(&args.files)?;
 76→
 77→    let (workspace, repo) = common::load_repo(&args.repo)?;
 78→
 79→    let spec = common::resolve_spec(
 80→        args.pos_rev.as_deref(),
 81→        args.pos_count,
 82→        &args.revision,
 83→        args.limit,
 84→        "@",
 85→    );
 86→
 87→    let (ids, anchor_index) = common::collect_ids(
 88→        &workspace,
 89→        &repo,
 90→        &spec.rev,
 91→        spec.desc_count,
 92→        spec.anc_count,
 93→    )?;
 94→
 95→    let mut first = true;
 96→    for (i, commit_id) in ids.iter().enumerate() {
 97→        if !first {
 98→            println!("────────────────────────────────────────");
 99→        }
100→        first = false;
101→
102→        let commit = repo.store().get_commit(commit_id)?;
103→        show_one_commit(&commit, &workspace, &repo, file_limit, i == anchor_index)?;
104→    }
105→
106→    Ok(())
107→}
108→
109→fn show_one_commit(
110→    commit: &Commit,
111→    workspace: &Workspace,
112→    repo: &Arc<ReadonlyRepo>,
113→    file_limit: FileLimit,
114→    is_primary: bool,
115→) -> Result<(), Box<dyn std::error::Error>> {
116→    // Author
117→    let author = commit.author();
118→    println!(
119→        "Author:    {} <{}> ({})",
120→        author.name,
121→        author.email,
122→        format_timestamp(&author.timestamp)
123→    );
124→
125→    // Committer
126→    let committer = commit.committer();
127→    println!(
128→        "Committer: {} <{}> ({})",
129→        committer.name,
130→        committer.email,
131→        format_timestamp(&committer.timestamp)
132→    );
133→
134→    // Ids
135→    let ids_line = common::format_commit_short(commit);
136→    if is_primary {
137→        println!("Ids:       {}", common::bold(&ids_line));
138→    } else {
139→        println!("Ids:       {ids_line}");
140→    }
141→
142→    // Parents
143→    let root_commit_id = repo.store().root_commit_id().clone();
144→    for parent_id in commit.parent_ids() {
145→        if *parent_id == root_commit_id {
146→            continue;
147→        }
148→        let parent = repo.store().get_commit(parent_id)?;
149→        println!("Parent:    {}", common::format_commit_short(&parent));
150→    }
151→
152→    // Children
153→    let children_ids =
154→        common::resolve_revset(workspace, repo, &format!("children({})", commit.id().hex()))?;
155→    for child_id in &children_ids {
156→        if *child_id == root_commit_id {
157→            continue;
158→        }
159→        let child = repo.store().get_commit(child_id)?;
160→        println!("Child:     {}", common::format_commit_short(&child));
161→    }
162→
163→    // Branches
164→    let branches_str = format_branches(commit, workspace, repo)?;
165→    println!("Branches:  {branches_str}");
166→
167→    // Follows
168→    let follows = find_nearest_tag(commit, workspace, repo, true)?;
169→    println!("Follows:   {}", follows.as_deref().unwrap_or(""));
170→
171→    // Precedes
172→    let precedes = find_nearest_tag(commit, workspace, repo, false)?;
173→    println!("Precedes:  {}", precedes.as_deref().unwrap_or(""));
174→
175→    // Description (body only — title is on the Ids line)
176→    print_description(commit);
177→
178→    // Changed files
179→    if file_limit != FileLimit::None {
180→        print_diff(commit, repo, file_limit)?;
181→    }
182→
183→    Ok(())
184→}
185→
186→fn find_nearest_tag(
187→    commit: &Commit,
188→    workspace: &Workspace,
189→    repo: &Arc<ReadonlyRepo>,
190→    ancestor: bool,
191→) -> Result<Option<String>, Box<dyn std::error::Error>> {
192→    let commit_hex = commit.id().hex();
193→
194→    let revset_str = if ancestor {
195→        format!("heads(tags() & ::{})", commit_hex)
196→    } else {
197→        format!("roots(tags() & {}::)", commit_hex)
198→    };
199→
200→    let tag_ids = common::resolve_revset(workspace, repo, &revset_str)?;
201→    if tag_ids.is_empty() {
202→        return Ok(None);
203→    }
204→
205→    let tag_id = &tag_ids[0];
206→    let view = repo.view();
207→    for (name, local_remote) in view.tags() {
208→        if local_remote.local_target.added_ids().any(|id| id == tag_id) {
209→            return Ok(Some(name.as_str().to_string()));
210→        }
211→    }
212→
213→    Ok(None)
214→}
215→
216→fn format_branches(
217→    commit: &Commit,
218→    workspace: &Workspace,
219→    repo: &Arc<ReadonlyRepo>,
220→) -> Result<String, Box<dyn std::error::Error>> {
221→    let commit_hex = commit.id().hex();
222→    let view = repo.view();
223→    let mut names: Vec<String> = Vec::new();
224→
225→    for (name, local_remote) in view.bookmarks() {
226→        for bookmark_id in local_remote.local_target.added_ids() {
227→            let revset_str = format!("{} & ::{}", commit_hex, bookmark_id.hex());
228→            let results = common::resolve_revset(workspace, repo, &revset_str)?;
229→            if !results.is_empty() {
230→                names.push(name.as_str().to_string());
231→                break;
232→            }
233→        }
234→
235→        for (remote_name, remote_ref) in &local_remote.remote_refs {
236→            if remote_name.as_str() == "git" {
237→                continue;
238→            }
239→            for bookmark_id in remote_ref.target.added_ids() {
240→                let revset_str = format!("{} & ::{}", commit_hex, bookmark_id.hex());
241→                let results = common::resolve_revset(workspace, repo, &revset_str)?;
242→                if !results.is_empty() {
243→                    names.push(format!("{}@{}", name.as_str(), remote_name.as_str()));
244→                    break;
245→                }
246→            }
247→        }
248→    }
249→
250→    Ok(names.join(", "))
251→}
