253→fn format_timestamp(ts: &jj_lib::backend::Timestamp) -> String {
254→    let millis = ts.timestamp.0;
255→    let secs = millis / 1000;
256→    let tz_minutes = ts.tz_offset;
257→
258→    let dt = chrono::DateTime::from_timestamp(secs, 0)
259→        .unwrap_or_default()
260→        .with_timezone(
261→            &chrono::FixedOffset::east_opt(tz_minutes * 60).unwrap_or(chrono::Utc.fix()),
262→        );
263→
264→    dt.format("%Y-%m-%d %H:%M:%S").to_string()
265→}
266→
267→fn print_description(commit: &Commit) {
268→    let desc = commit.description();
269→    let body: String = desc
270→        .lines()
271→        .skip(1)
272→        .skip_while(|l| l.is_empty())
273→        .collect::<Vec<_>>()
274→        .join("\n");
275→
276→    println!("Description:");
277→    for line in body.lines() {
278→        println!("    {line}");
279→    }
280→}
281→
282→fn print_diff(
283→    commit: &Commit,
284→    repo: &Arc<ReadonlyRepo>,
285→    file_limit: FileLimit,
286→) -> Result<(), Box<dyn std::error::Error>> {
287→    let parent_tree = commit.parent_tree(repo.as_ref()).block_on()?;
288→    let commit_tree = commit.tree();
289→
290→    let diff_iter = TreeDiffIterator::new(&parent_tree, &commit_tree, &EverythingMatcher);
291→
292→    let mut lines: Vec<String> = Vec::new();
293→    for entry in diff_iter {
294→        let diff = entry.values?;
295→        let before = diff.before.as_resolved().cloned().flatten();
296→        let after = diff.after.as_resolved().cloned().flatten();
297→
298→        if matches!(&before, Some(TreeValue::Tree(_))) || matches!(&after, Some(TreeValue::Tree(_)))
299→        {
300→            continue;
301→        }
302→
303→        let path_str = entry.path.as_internal_file_string().to_string();
304→
305→        let line = match (before, after) {
306→            (None, Some(value)) => {
307→                format!("    Added {} {path_str}", file_type_str(&value))
308→            }
309→            (Some(_), None) => {
310→                format!(
311→                    "    Removed {} {path_str}",
312→                    file_type_str_from_merged(&diff.before),
313→                )
314→            }
315→            (Some(_), Some(value)) => {
316→                format!("    Modified {} {path_str}", file_type_str(&value))
317→            }
318→            (None, None) => continue,
319→        };
320→        lines.push(line);
321→    }
322→
323→    let total = lines.len();
324→    let cap = match file_limit {
325→        FileLimit::All | FileLimit::None => 0,
326→        FileLimit::Cap(n) => n,
327→    };
328→    let show_all = cap == 0 || total <= cap;
329→
330→    if show_all {
331→        println!("Changed files: {total}");
332→        for line in &lines {
333→            println!("{line}");
334→        }
335→    } else {
336→        println!("Changed files: {total}, showing first {cap}");
337→        for line in &lines[..cap] {
338→            println!("{line}");
339→        }
340→    }
341→
342→    Ok(())
343→}
344→
345→fn file_type_str(value: &TreeValue) -> &'static str {
346→    match value {
347→        TreeValue::File {
348→            executable: false, ..
349→        } => "regular file",
350→        TreeValue::File {
351→            executable: true, ..
352→        } => "executable file",
353→        TreeValue::Symlink(_) => "symlink",
354→        TreeValue::Tree(_) => "tree",
355→        TreeValue::GitSubmodule(_) => "git submodule",
356→    }
357→}
358→
359→fn file_type_str_from_merged(merged: &jj_lib::merge::Merge<Option<TreeValue>>) -> &'static str {
360→    if let Some(Some(value)) = merged.as_resolved() {
361→        file_type_str(value)
362→    } else {
363→        "file"
364→    }
365→}
366→

