259→pub fn load_repo(
260→    path: &Path,
261→) -> Result<(Workspace, Arc<ReadonlyRepo>), Box<dyn std::error::Error>> {
262→    let config = StackedConfig::with_defaults();
263→    let settings = UserSettings::from_config(config)?;
264→    let store_factories = StoreFactories::default();
265→    let working_copy_factories = default_working_copy_factories();
266→
267→    let workspace = Workspace::load(&settings, path, &store_factories, &working_copy_factories)?;
268→    let repo = workspace.repo_loader().load_at_head().block_on()?;
269→
270→    Ok((workspace, repo))
271→}
