use std::path::PathBuf;
use std::process::Command;

use clap::Args;
use jj_lib::object_id::ObjectId;
use jj_lib::repo::Repo;

use crate::common;

#[derive(Args, Debug)]
pub struct FixOchidArgs {
    /// Revision(s) to fix
    #[arg(short, long, default_value = "@")]
    pub revision: String,

    /// Path to jj repo
    #[arg(short = 'R', long, default_value = ".")]
    pub repo: PathBuf,

    /// Path prefix for the other repo (e.g. /.claude/ or /)
    #[arg(long = "other-path")]
    pub other_path: String,

    /// New title to replace the first line (optional)
    #[arg(long)]
    pub title: Option<String>,

    /// Preview changes without writing
    #[arg(long)]
    pub dry_run: bool,

    /// Number of commits to fix
    #[arg(short = 'n', long = "commits", value_name = "COMMITS")]
    pub limit: Option<usize>,
}

/// Fix the ochid trailer in a commit description.
///
/// If the description has an `ochid:` line, ensure the value starts with `other_path`.
/// If it already has a path prefix starting with `/`, replace it.
/// If it's a bare changeID, prepend `other_path`.
/// Normalizes the changeID to 12 characters.
fn fix_ochid_in_description(desc: &str, other_path: &str, new_title: Option<&str>) -> String {
    let mut lines: Vec<String> = desc.lines().map(|l| l.to_string()).collect();

    // Fix title if requested
    if let Some(title) = new_title {
        if !lines.is_empty() {
            lines[0] = title.to_string();
        }
    }

    // Fix ochid trailer
    for line in &mut lines {
        let trimmed = line.trim();
        if let Some(value) = trimmed.strip_prefix("ochid:") {
            let value = value.trim();
            // Extract the bare changeID (strip any existing path prefix)
            let bare_id = if let Some(pos) = value.rfind('/') {
                &value[pos + 1..]
            } else {
                value
            };
            // Normalize to 12 chars
            let short_id = &bare_id[..bare_id.len().min(12)];
            // Reconstruct with correct path
            let prefix = if other_path.ends_with('/') {
                other_path.to_string()
            } else {
                format!("{other_path}/")
            };
            *line = format!("ochid: {prefix}{short_id}");
        }
    }

    // Preserve trailing newline if original had one
    let mut result = lines.join("\n");
    if desc.ends_with('\n') {
        result.push('\n');
    }
    result
}

pub fn fix_ochid(args: &FixOchidArgs) -> Result<(), Box<dyn std::error::Error>> {
    let (workspace, repo) = common::load_repo(&args.repo)?;

    let revset_str = if let Some(n) = args.limit {
        format!("ancestors({}, {})", args.revision, n)
    } else {
        args.revision.clone()
    };

    let ids = common::resolve_revset(&workspace, &repo, &revset_str)?;
    if ids.is_empty() {
        return Err(format!("no commits found for revision '{}'", args.revision).into());
    }

    let root_id = repo.store().root_commit_id().clone();
    let mut fixed = 0;
    let mut skipped = 0;

    for commit_id in &ids {
        if *commit_id == root_id {
            continue;
        }
        let commit = repo.store().get_commit(commit_id)?;
        let desc = commit.description();
        let change_hex = jj_lib::hex_util::encode_reverse_hex(commit.change_id().as_bytes());
        let change_short = &change_hex[..change_hex.len().min(12)];

        let new_desc = fix_ochid_in_description(desc, &args.other_path, args.title.as_deref());

        if new_desc == desc {
            skipped += 1;
            if args.dry_run {
                println!("skip {change_short}  (no change needed)");
            }
            continue;
        }

        if args.dry_run {
            let first_line = new_desc.lines().next().unwrap_or("");
            println!("fix  {change_short}  {first_line}");
            // Show the ochid line
            for line in new_desc.lines() {
                if line.trim().starts_with("ochid:") {
                    println!(
                        "     ochid: {}",
                        line.trim().strip_prefix("ochid:").unwrap().trim()
                    );
                }
            }
        } else {
            let status = Command::new("jj")
                .arg("describe")
                .arg("-m")
                .arg(&new_desc)
                .arg("-r")
                .arg(&commit_id.hex())
                .arg("-R")
                .arg(&args.repo)
                .arg("--ignore-immutable")
                .stdout(std::process::Stdio::null())
                .stderr(std::process::Stdio::inherit())
                .status()?;
            if !status.success() {
                return Err(format!(
                    "jj describe failed for {} (exit {})",
                    change_short,
